    // Advance watermark to make the window late
    // Window [100, 103) with maxTimestamp=102 (103-1), allowedLateness=5
    // Cleanup time = 102 + 5 = 107
    // Watermark 108 means window is past cleanup time, so it's late
    testHarness.processWatermark(new Watermark(108));
    expected.add(new Watermark(108));

    // Send a late element with timestamp 99 that would create window [99, 102)
    // This should merge with existing [100, 103) creating [99, 103)
