   449→    @Override
   450→    public void onEventTime(InternalTimer<K, W> timer) throws Exception {
   451→        triggerContext.key = timer.getKey();
   452→        triggerContext.window = timer.getNamespace();
   453→
   454→        MergingWindowSet<W> mergingWindows;
   455→
   456→        if (windowAssigner instanceof MergingWindowAssigner) {
   457→            mergingWindows = getMergingWindowSet();
   458→            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
   459→            if (stateWindow == null) {
   460→                // Timer firing for non-existent window, this can only happen if a
   461→                // trigger did not clean up timers. We have already cleared the merging
   462→                // window and therefore the Trigger state, however, so nothing to do.
   463→                return;
   464→            } else {
   465→                windowState.setCurrentNamespace(stateWindow);
   466→            }
   467→        } else {
   468→            windowState.setCurrentNamespace(triggerContext.window);
   469→            mergingWindows = null;
   470→        }
   471→
   472→        TriggerResult triggerResult = triggerContext.onEventTime(timer.getTimestamp());
   473→
   474→        if (triggerResult.isFire()) {
   475→            ACC contents = windowState.get();
   476→            if (contents != null) {
   477→                emitWindowContents(triggerContext.window, contents);
   478→            }
   479→        }
   480→
   481→        if (triggerResult.isPurge()) {
   482→            windowState.clear();
   483→        }
   484→
   485→        if (windowAssigner.isEventTime()
   486→                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
   487→            clearAllState(triggerContext.window, windowState, mergingWindows);
   488→        }
   489→
   490→        if (mergingWindows != null) {
   491→            // need to make sure to update the merging state in state
   492→            mergingWindows.persist();
   493→        }
   494→    }
   495→
   496→    @Override
   497→    public void onProcessingTime(InternalTimer<K, W> timer) throws Exception {
   498→        triggerContext.key = timer.getKey();
   499→        triggerContext.window = timer.getNamespace();
   500→
   501→        MergingWindowSet<W> mergingWindows;
   502→
   503→        if (windowAssigner instanceof MergingWindowAssigner) {
   504→            mergingWindows = getMergingWindowSet();
   505→            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
   506→            if (stateWindow == null) {
   507→                // Timer firing for non-existent window, this can only happen if a
   508→                // trigger did not clean up timers. We have already cleared the merging
   509→                // window and therefore the Trigger state, however, so nothing to do.
   510→                return;
   511→            } else {
   512→                windowState.setCurrentNamespace(stateWindow);
   513→            }
   514→        } else {
   515→            windowState.setCurrentNamespace(triggerContext.window);
   516→            mergingWindows = null;
   517→        }
   518→
   519→        TriggerResult triggerResult = triggerContext.onProcessingTime(timer.getTimestamp());
   520→
   521→        if (triggerResult.isFire()) {
   522→            ACC contents = windowState.get();
   523→            if (contents != null) {
   524→                emitWindowContents(triggerContext.window, contents);
   525→            }
   526→        }
   527→
   528→        if (triggerResult.isPurge()) {
   529→            windowState.clear();
   530→        }
   531→
   532→        if (!windowAssigner.isEventTime()
   533→                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
   534→            clearAllState(triggerContext.window, windowState, mergingWindows);
   535→        }
   536→
   537→        if (mergingWindows != null) {
   538→            // need to make sure to update the merging state in state
   539→            mergingWindows.persist();
   540→        }
   541→    }
